sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    var reqSysId = current.request.toString();
    if (!reqSysId) return;

    // جلب كل الـ RITMs تحت هذا الـ REQ
    var allRITMs = new GlideRecord('sc_req_item');
    allRITMs.addQuery('request', reqSysId);
    allRITMs.query();

    var stats = {
        total: 0,
        requested: 0,
        approved: 0,
        rejected: 0,
        readyForPickup: 0,
        completed: 0
    };

    while (allRITMs.next()) {
        stats.total++;
        var stage = allRITMs.stage.toString();
        var approval = allRITMs.approval_state.toString();

        if (stage == 'complete') stats.completed++;
        else if (stage == 'ready_for_pickup') stats.readyForPickup++;

        if (approval == 'approved') stats.approved++;
        else if (approval == 'rejected' || approval == 'not_required') stats.rejected++;
        else if (approval == 'requested') stats.requested++;
    }

    var newReqState = '';
    var newReqStage = ''; // لو حابة تستخدمي حقل مخصص

    // 1. كل حاجة اكتملت
    if (stats.completed == stats.total) {
        newReqState = 'closed_complete';
        newReqStage = 'Completed';
    }
    // 2. كل حاجة مرفوضة
    else if (stats.rejected == stats.total) {
        newReqState = 'closed_incomplete';
        newReqStage = 'Rejected';
    }
    // 3. فيه حاجات جاهزة وخلاص (كل الـ approved بقت ready_for_pickup)
    else if (stats.readyForPickup == stats.approved && stats.approved > 0) {
        newReqState = 'in_progress';
        newReqStage = 'Ready for Pickup';
    }
    // 4. فيه حاجات اتعملها approve بس لسه مش جاهزة
    else if (stats.approved > 0 && stats.requested == 0) {
        newReqState = 'in_progress';
        newReqStage = 'Partially Approved';
    }
    // 5. فيه approvals و requesteds
    else if (stats.approved > 0 && stats.requested > 0) {
        newReqState = 'in_progress';
        newReqStage = 'Partial Approval – Pending';
    }
    // 6. لسه في انتظار الموافقات
    else if (stats.requested > 0) {
        newReqState = 'pending_approval';
        newReqStage = 'Under Review';
    }
    // 7. (افتراضي) لو مفيش أي من دول
    else {
        newReqState = 'new';
        newReqStage = 'New';
    }

    // تحديث الـ REQ
    var req = new GlideRecord('sc_request');
    if (req.get(reqSysId)) {
        req.state = newReqState;
        req.stage = newReqStage; // تأكدي من وجود الحقل ده، وإلا استخدمي description مؤقتاً
        req.update();
    }
})(current, previous);
